import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  ParseIntPipe,
  Query,
  UseGuards,
  Req,
  UnauthorizedException,
  ForbiddenException,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import type { Request } from 'express';
import { ApiTags, ApiOperation, ApiResponse, ApiHeader } from '@nestjs/swagger';
import {
  UsersService,
  type ChangePasswordDto,
  type CreateUserDto,
  type UpdateProfileDto,
} from './users.service';
import { User } from '../entities/user.entity';
import { PermissionsGuard } from '../auth/guards/permissions.guard';
import { Public, Permissions } from '../auth/decorators/public.decorator';
import { PERMISSIONS } from '../auth/permissions.constants';
import { RbacService } from '../auth/rbac.service';
import { parseXUserId } from '../auth/request-user.util';

export type PublicUser = {
  id: number;
  createdAt: Date;
  updatedAt: Date;
  email: string;
  fullName: string;
  phone?: string;
  address?: string;
  isActive: boolean;
  roles: Array<{ code: string; name: string }>;
  /** Có giá trị khi tài khoản đang trong thùng rác (chỉ admin thấy qua API thùng rác). */
  deletedAt?: Date | null;
};

export type LoginUser = PublicUser & { permissions: string[] };

function toPublicUser(user: User): PublicUser {
  const roles = user.userRoleLinks.isInitialized()
    ? user.userRoleLinks.getItems().map((l) => ({
        code: l.role.code,
        name: l.role.name,
      }))
    : [];
  return {
    id: user.id,
    createdAt: user.createdAt,
    updatedAt: user.updatedAt,
    email: user.email,
    fullName: user.fullName,
    phone: user.phone,
    address: user.address,
    isActive: user.isActive,
    roles,
    deletedAt: user.deletedAt ?? null,
  };
}

@ApiTags('users')
@Controller('users')
@UseGuards(PermissionsGuard)
@ApiHeader({
  name: 'X-User-Id',
  required: false,
  description:
    'ID user đang thao tác — bắt buộc với các API có kiểm tra quyền; với giỏ hàng / xem hồ sơ của chính mình phải trùng id trong URL.',
})
export class UsersController {
  constructor(
    private readonly usersService: UsersService,
    private readonly rbac: RbacService,
  ) {}

  @Post('login')
  @Public()
  @ApiOperation({ summary: 'Validate user credentials' })
  @ApiResponse({ status: 200, description: 'Return user if valid' })
  async validateUser(
    @Body('email') email: string,
    @Body('password') password: string,
  ): Promise<LoginUser | null> {
    const user = await this.usersService.validateUser(email, password);
    if (!user) {
      return null;
    }
    // Luôn load lại kèm userRoleLinks.role — tránh identity map thiếu collection sau validate.
    const loaded = await this.usersService.findOne(user.id);
    const publicUser = toPublicUser(loaded);
    const codes = await this.rbac.getEffectivePermissionCodes(loaded.id);
    const permissions = [...codes].sort();
    const hasSuperRole = publicUser.roles.some(
      (r) => r.code?.trim().toLowerCase() === 'super_admin',
    );
    if (hasSuperRole && !permissions.includes('*')) {
      permissions.unshift('*');
    }
    return {
      ...publicUser,
      permissions,
    };
  }

  @Get()
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({
    summary: 'Get all users (hoặc ?q=&page=&limit= phân trang + tìm nhanh)',
  })
  @ApiResponse({ status: 200, description: 'Return all users or paged' })
  async findAll(
    @Query('q') q?: string,
    @Query('page') pageStr?: string,
    @Query('limit') limitStr?: string,
  ): Promise<PublicUser[] | { items: PublicUser[]; total: number }> {
    const page =
      pageStr !== undefined && pageStr !== ''
        ? parseInt(pageStr, 10)
        : Number.NaN;
    const limit =
      limitStr !== undefined && limitStr !== ''
        ? parseInt(limitStr, 10)
        : Number.NaN;
    if (
      Number.isFinite(page) &&
      Number.isFinite(limit) &&
      page >= 1 &&
      limit >= 1 &&
      limit <= 200
    ) {
      const res = await this.usersService.findPage({
        q: q?.trim() || undefined,
        page,
        limit,
      });
      return { items: res.items.map(toPublicUser), total: res.total };
    }
    const users = await this.usersService.findAll();
    return users.map(toPublicUser);
  }

  @Get('trashed')
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({ summary: 'Tài khoản đã xóa tạm' })
  async listTrashed(
    @Query('page') pageStr?: string,
    @Query('limit') limitStr?: string,
    @Query('q') q?: string,
  ): Promise<{ items: PublicUser[]; total: number }> {
    const page =
      pageStr !== undefined && pageStr !== ''
        ? parseInt(pageStr, 10)
        : undefined;
    const limit =
      limitStr !== undefined && limitStr !== ''
        ? parseInt(limitStr, 10)
        : undefined;
    const res = await this.usersService.listTrashed({
      page,
      limit,
      q: q?.trim() || undefined,
    });
    return { items: res.items.map(toPublicUser), total: res.total };
  }

  @Get('email/:email')
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({ summary: 'Get user by email' })
  @ApiResponse({ status: 200, description: 'Return the user' })
  async findByEmail(@Param('email') email: string): Promise<PublicUser | null> {
    const user = await this.usersService.findByEmail(email);
    return user ? toPublicUser(user) : null;
  }

  @Get('by-role/:code')
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({ summary: 'Get users by role code (vd: admin, sales)' })
  @ApiResponse({ status: 200, description: 'Return users with role' })
  async findByRoleCode(@Param('code') code: string): Promise<PublicUser[]> {
    const users = await this.usersService.findByRoleCode(code);
    return users.map(toPublicUser);
  }

  /** Đại lý B2B (role `customer`) — đọc được với `products.read` (cùng quyền menu Đại lý & Cửa hàng). */
  @Get('dealers')
  @Permissions(PERMISSIONS.PRODUCTS_READ)
  @ApiOperation({ summary: 'Danh sách tài khoản đại lý (role customer)' })
  @ApiResponse({ status: 200, description: 'Return dealer users' })
  async listDealers(): Promise<PublicUser[]> {
    const users = await this.usersService.findByRoleCode('customer');
    return users.map(toPublicUser);
  }

  @Get(':id/cart')
  @Public()
  @ApiOperation({ summary: 'Giỏ hàng đã lưu (JSON) theo user' })
  async getCart(
    @Param('id', ParseIntPipe) id: number,
    @Req() req: Request,
  ): Promise<{ lines: unknown[] }> {
    await this.assertSelfOrManage(req, id);
    return this.usersService.getCartSnapshot(id);
  }

  @Put(':id/cart')
  @Public()
  @ApiOperation({ summary: 'Lưu giỏ hàng JSON cho user' })
  async saveCart(
    @Param('id', ParseIntPipe) id: number,
    @Body() body: { lines: unknown[] },
    @Req() req: Request,
  ): Promise<{ ok: true }> {
    await this.assertSelfOrManage(req, id);
    await this.usersService.saveCartSnapshot(id, body);
    return { ok: true };
  }

  @Put(':id/profile')
  @Public()
  @ApiOperation({
    summary:
      'Cập nhật hồ sơ (tên, SĐT, địa chỉ cửa hàng) — chỉ chính chủ hoặc users.manage',
  })
  async updateProfile(
    @Param('id', ParseIntPipe) id: number,
    @Body() body: UpdateProfileDto,
    @Req() req: Request,
  ): Promise<PublicUser> {
    await this.assertSelfOrManage(req, id);
    const user = await this.usersService.updateProfile(id, body);
    return toPublicUser(user);
  }

  @Post(':id/change-password')
  @Public()
  @ApiOperation({
    summary:
      'Đổi mật khẩu — chỉ chính chủ (xác minh mật khẩu hiện tại) hoặc users.manage',
  })
  async changePassword(
    @Param('id', ParseIntPipe) id: number,
    @Body() body: ChangePasswordDto,
    @Req() req: Request,
  ): Promise<{ ok: true }> {
    await this.assertSelfOrManage(req, id);
    await this.usersService.changePassword(id, body);
    return { ok: true };
  }

  @Get(':id')
  @Public()
  @ApiOperation({ summary: 'Get user by id' })
  @ApiResponse({ status: 404, description: 'User not found' })
  async findOne(
    @Param('id', ParseIntPipe) id: number,
    @Req() req: Request,
  ): Promise<PublicUser> {
    await this.assertSelfOrManage(req, id);
    const user = await this.usersService.findOne(id);
    return toPublicUser(user);
  }

  @Post()
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({ summary: 'Create a new user' })
  @ApiResponse({ status: 201, description: 'User created' })
  @ApiResponse({ status: 409, description: 'Email already exists' })
  async create(@Body() userData: CreateUserDto): Promise<PublicUser> {
    const user = await this.usersService.create(userData);
    return toPublicUser(user);
  }

  @Put(':id')
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({
    summary: 'Update a user (body.roleCodes thay thế toàn bộ role)',
  })
  @ApiResponse({ status: 200, description: 'User updated' })
  async update(
    @Param('id', ParseIntPipe) id: number,
    @Body() userData: Partial<User> & { roleCodes?: string[] },
  ): Promise<PublicUser> {
    const user = await this.usersService.update(id, userData);
    return toPublicUser(user);
  }

  @Post(':id/restore')
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({ summary: 'Khôi phục tài khoản từ thùng rác' })
  async restore(@Param('id', ParseIntPipe) id: number): Promise<PublicUser> {
    const user = await this.usersService.restore(id);
    return toPublicUser(user);
  }

  @Delete(':id/permanent')
  @HttpCode(HttpStatus.NO_CONTENT)
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({
    summary: 'Xóa vĩnh viễn tài khoản (chỉ khi đang trong thùng rác)',
  })
  async purgeTrashed(@Param('id', ParseIntPipe) id: number): Promise<void> {
    return this.usersService.purgeTrashed(id);
  }

  @Delete(':id')
  @Permissions(PERMISSIONS.USERS_MANAGE)
  @ApiOperation({ summary: 'Xóa tạm tài khoản' })
  @ApiResponse({ status: 200, description: 'User moved to trash' })
  async delete(@Param('id', ParseIntPipe) id: number): Promise<void> {
    return this.usersService.delete(id);
  }

  private async assertSelfOrManage(
    req: Request,
    targetUserId: number,
  ): Promise<void> {
    const actor = parseXUserId(req);
    if (actor === null) {
      throw new UnauthorizedException(
        'Gửi header X-User-Id trùng id tài khoản hoặc dùng tài khoản có quyền users.manage.',
      );
    }
    if (actor === targetUserId) {
      return;
    }
    const ok = await this.rbac.userHasAll(actor, [PERMISSIONS.USERS_MANAGE]);
    if (!ok) {
      throw new ForbiddenException(
        'Chỉ xem/sửa dữ liệu của chính mình, hoặc cần quyền users.manage.',
      );
    }
  }
}

